// Date is inside body object in the webhook
const dateStr = $('Webhook').item.json.body.date;

const parts = dateStr.split('-');
const year = parseInt(parts[0]);
const month = parseInt(parts[1]) - 1;
const day = parseInt(parts[2]);

const date = new Date(Date.UTC(year, month, day));
const days = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
const dayName = days[date.getUTCDay()];

const lawyerData = $input.item.json;
const workingHours = lawyerData.working_hours[dayName];

return {
  json: {
    day_name: dayName,
    working_hours: workingHours || null,
    lawyer_name: lawyerData.name,
    lawyer_id: lawyerData.id
  }
};

// Get data from previous nodes
const dateStr = $('Webhook').item.json.body.date;
const durationMins = parseInt($('Webhook').item.json.body.duration_minutes) || 60;
const workingHours = $('Get Day of Week').item.json.working_hours;
const lawyerName = $('Get Day of Week').item.json.lawyer_name;
const lawyerId = $('Get Day of Week').item.json.lawyer_id;

// Get existing appointments - may be empty array
const existingApts = $('Get Existing Appointments').all() || [];

// If not a working day
if (!workingHours) {
  return [{
    json: {
      lawyer_id: lawyerId,
      lawyer_name: lawyerName,
      date: dateStr,
      available: false,
      slots: [],
      total_available: 0,
      reason: "Not a working day"
    }
  }];
}

// Parse working hours
const [startHour, startMin] = workingHours.start.split(':').map(Number);
const [endHour, endMin] = workingHours.end.split(':').map(Number);

// Helper to format time to 12hr
function formatTime(h, m) {
  const period = h >= 12 ? 'PM' : 'AM';
  const hour12 = h % 12 || 12;
  return `${hour12}:${String(m).padStart(2, '0')} ${period}`;
}

// Generate 30-minute slots
const slots = [];
let currentHour = startHour;
let currentMin = startMin;

while (
  currentHour < endHour || 
  (currentHour === endHour && currentMin < endMin)
) {
  const slotTime = `${String(currentHour).padStart(2, '0')}:${String(currentMin).padStart(2, '0')}`;

  // Calculate slot end time
  const totalMins = currentHour * 60 + currentMin + durationMins;
  const endH = Math.floor(totalMins / 60);
  const endM = totalMins % 60;
  const slotEnd = `${String(endH).padStart(2, '0')}:${String(endM).padStart(2, '0')}`;

  // Skip lunch hour (12:00 - 13:00)
  const isLunch = (currentHour === 12);

  // Skip if slot end goes past working hours
  const pastEndOfDay = endH > endHour || (endH === endHour && endM > endMin);

  if (!isLunch && !pastEndOfDay) {
    // Check conflicts with existing appointments
    let hasConflict = false;
    for (const apt of existingApts) {
      const aptStart = apt.json.start_time;
      const aptEnd = apt.json.end_time;
      if (slotTime < aptEnd && slotEnd > aptStart) {
        hasConflict = true;
        break;
      }
    }

    if (!hasConflict) {
      slots.push({
        time: slotTime,
        formatted: formatTime(currentHour, currentMin)
      });
    }
  }

  // Move to next 30-min slot
  currentMin += 30;
  if (currentMin >= 60) {
    currentMin = 0;
    currentHour++;
  }
}

return [{
  json: {
    lawyer_id: lawyerId,
    lawyer_name: lawyerName,
    date: dateStr,
    available: slots.length > 0,
    slots: slots,
    total_available: slots.length
  }
}];
